+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?/g, '\
');
+}
+
+function stripFrame(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']) {
+  if (mode === 'node' || mode === 'node_and_superjson') {
+    if (line.includes('node:internal')) return true;
+  }
+  if (mode === 'superjson' || mode === 'node_and_superjson') {
+    return ['src/transformer.ts', 'src/plainer.ts', 'src/index.ts'].some(part =>
+      line.includes(part)
+    );
+  }
+  return false;
+}
+
+function redactLine(line: string, options: NormalizedErrorStackOptions): string {
+  if (options.redactPaths === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/');
+    return line.replace(new RegExp(cwd.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&'), 'g'), '');
+  }
+  if (options.redactPaths === 'basename') {
+    return line.replace(/(?:file:\\/\\/)?(?:[A-Za-z]:)?(?:[\\\\/][^()\\s:]+)+/g, path => {
+      const parts = path.replace(/\\\\/g, '/').split('/');
+      return parts[parts.length - 1];
+    });
+  }
+  return line;
+}
+
+function initialLines(stack: string, options: NormalizedErrorStackOptions): string[] {
+  const text = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  const lines = text.split('\
');
+  if (options.trimLeadingWhitespace) {
+    return lines.map((line, index) => (index === 0 ? line : line.replace(/^\\s+/, '')));
+  }
+  return lines;
+}
+
+export function processStackString(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): string {
+  let lines = initialLines(stack, options).map(line => redactLine(line, options));
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  return [lines[0], ...lines.slice(1).filter(line => !stripFrame(line, options.stripInternalFrames))].join('\
');
+}
+
+export function processStackFrames(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): Array<{ raw: string }> {
+  let lines = initialLines(stack, options);
+  lines = [lines[0], ...lines.slice(1).filter(line => !stripFrame(line, options.stripInternalFrames))];
+  lines = lines.map(line => redactLine(line, options));
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  return lines.map(raw => ({ raw }));
+}
