+function serializeError(
+  error: Error,
+  superJson: SuperJSON,
+  annotation: 'Error' | 'Error/stack' | 'Error/frames'
+): Record<string, any> {
+  const options = superJson.errorStackOptions;
+  const enhanced = annotation !== 'Error' && !!options;
+  const baseError: Record<string, any> = {
+    name: error.name,
+    message:
+      enhanced && options.sanitizeMessage
+        ? sanitizeMessage(error.message)
+        : error.message,
+  };
+
+  if (!enhanced) {
+    if ('cause' in error) baseError.cause = (error as any).cause;
+  } else {
+    const cause = (error as any).cause;
+    const depth = superJson.getErrorCauseDepth(error);
+    const causeAllowed =
+      cause instanceof Error &&
+      (options.includeCauses === 'direct'
+        ? depth === 0
+        : options.includeCauses === 'deep' && depth < options.maxCauseDepth);
+    if (causeAllowed) {
+      superJson.setErrorCauseDepth(cause, depth + 1);
+      baseError.cause = cause;
+    }
+  }
+
+  if (isAggregateError(error)) baseError.errors = error.errors;
+
+  superJson.allowedErrorProps.forEach(prop => {
+    if (enhanced && (prop === 'stack' || prop === 'stackFrames')) return;
+    baseError[prop] = (error as any)[prop];
